# frozen_string_literal: true

# Plaid API client
class PlaidApi
  def initialize
    plaid_client_id = Anedot.secrets.plaid[:client_id]
    plaid_secret    = Anedot.secrets.plaid[:secret]
    plaid_env       = Anedot.secrets.plaid[:environment]

    configuration = Plaid::Configuration.new do |config|
      config.server_index = Plaid::Configuration::Environment[plaid_env]
      config.api_key["PLAID-CLIENT-ID"] = plaid_client_id
      config.api_key["PLAID-SECRET"] = plaid_secret
    end

    @api_client = Plaid::ApiClient.new(configuration)
  end

  def plaid
    @plaid ||= Plaid::PlaidApi.new(@api_client)
  end

  def link_token(client_user_id)
    plaid.link_token_create(
      Plaid::LinkTokenCreateRequest.new(
        {
          user: { client_user_id: },
          client_name: "Anedot",
          products: %w[auth],
          country_codes: ["US"],
          language: "en"
        }
      )
    ).link_token
  end

  def identity_link_token(user, options = {})
    name = {}
    name[:given_name] = options[:first_name]
    name[:family_name] = options[:last_name]
    address = {}
    address[:street] = options[:line1]
    address[:street2] = options[:line2]
    address[:city] = options[:city]
    address[:region] = options[:region]
    address[:postal_code] = options[:postal_code]
    address[:country] = options[:country] || "US"

    plaid.link_token_create(
      Plaid::LinkTokenCreateRequest.new(
        {
          user: {
            client_user_id: user.uid,
            name: name.compact_blank,
            email_address: options[:email],
            address: address.compact_blank
          }.compact_blank,
          client_name: "Anedot",
          products: %w[identity_verification],
          country_codes: ["US"],
          language: "en",
          identity_verification: {
            template_id: Anedot.secrets.plaid[:template_id]
          }
        }
      )
    ).link_token
  end

  def identity_verification_list(user_uid)
    plaid.identity_verification_list(
      Plaid::IdentityVerificationListRequest.new(
        template_id: Anedot.secrets.plaid[:template_id],
        client_user_id: user_uid
      )
    )
  end

  def identity_verification_get(identity_verification_id)
    plaid.identity_verification_get(
      Plaid::IdentityVerificationGetRequest.new(identity_verification_id:)
    )
  end

  def exchange_public_token(public_token)
    plaid.item_public_token_exchange(
      Plaid::ItemPublicTokenExchangeRequest.new(public_token:)
    ).access_token
  end

  def auth(access_token)
    plaid.auth_get(
      Plaid::AuthGetRequest.new(access_token:)
    )
  end

  def identity(access_token)
    plaid.identity_get(
      Plaid::IdentityGetRequest.new(access_token:)
    )
  end

  def institution(institution_id)
    plaid.institutions_get_by_id(
      Plaid::InstitutionsGetByIdRequest.new(institution_id:, country_codes: ["US"])
    )
  end
end
